import { useState, useEffect, useCallback } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import AdminLayout from '../components/admin/AdminLayout';
import authService from '../services/authService';
import api from '../services/api';

// Section types configuration
const SECTION_TYPES = [
  { type: 'hero', label: 'Hero', icon: 'fa-bolt', description: 'Grande bannière avec titre et CTA' },
  { type: 'features', label: 'Features/Caractéristiques', icon: 'fa-star', description: '列表形式展示特点或功能' },
  { type: 'benefits', label: 'Benefits/Avantages', icon: 'fa-handshake', description: '展示主要优势或好处' },
  { type: 'pricing', label: 'Pricing/Tarifs', icon: 'fa-tag', description: '展示定价方案' },
  { type: 'faq', label: 'FAQ', icon: 'fa-question-circle', description: '常见问题解答' },
  { type: 'testimonials', label: 'Testimonials/评价', icon: 'fa-quote-left', description: '客户评价展示' },
  { type: 'cta', label: 'CTA/行动号召', icon: 'fa-bullhorn', description: '行动号召区域' },
  { type: 'contact', label: 'Contact/联系', icon: 'fa-envelope', description: '联系信息区域' },
  { type: 'gallery', label: 'Gallery/图库', icon: 'fa-images', description: '图片展示' },
  { type: 'text_image', label: 'Text + Image/图文', icon: 'fa-align-left', description: '文字和图片组合' },
  { type: 'custom', label: 'Custom/自定义', icon: 'fa-code', description: '自定义内容区域' },
];

export default function PageBuilder() {
  const navigate = useNavigate();
  const { pageId } = useParams();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  // Page data
  const [page, setPage] = useState({
    slug: '',
    title: '',
    metaTitle: '',
    metaDescription: '',
    isPublished: false,
    sections: []
  });

  // UI state
  const [showPageModal, setShowPageModal] = useState(false);
  const [showSectionModal, setShowSectionModal] = useState(false);
  const [showSectionEditor, setShowSectionEditor] = useState(false);
  const [editingSection, setEditingSection] = useState(null);
  const [draggedSection, setDraggedSection] = useState(null);

  // Cards management
  const [showCardModal, setShowCardModal] = useState(false);
  const [editingCard, setEditingCard] = useState(null);
  const [cardSectionId, setCardSectionId] = useState(null);

  useEffect(() => {
    if (!authService.isAdmin()) {
      navigate('/login');
      return;
    }

    if (pageId) {
      loadPage(pageId);
    } else {
      setLoading(false);
    }
  }, [pageId]);

  const loadPage = async (id) => {
    try {
      setLoading(true);
      const response = await api.get(`/admin/pages/${id}`);
      const pageData = response.data;

      // Sort sections by position
      const sortedSections = (pageData.sections || []).sort((a, b) => a.position - b.position);

      setPage({
        ...pageData,
        sections: sortedSections
      });
    } catch (error) {
      console.error('Error loading page:', error);
      alert('Erreur lors du chargement de la page');
    } finally {
      setLoading(false);
    }
  };

  const handleSavePage = async () => {
    try {
      setSaving(true);

      const pageData = {
        slug: page.slug,
        title: page.title,
        metaTitle: page.metaTitle,
        metaDescription: page.metaDescription,
        isPublished: page.isPublished
      };

      if (pageId) {
        await api.put(`/admin/pages/${pageId}`, pageData);
      } else {
        const response = await api.post('/admin/pages', pageData);
        navigate(`/admin/page-builder/${response.data.id}`, { replace: true });
      }

      alert('Page sauvegardée !');
    } catch (error) {
      console.error('Error saving page:', error);
      alert('Erreur lors de la sauvegarde');
    } finally {
      setSaving(false);
    }
  };

  const handleDragStart = (e, section) => {
    setDraggedSection(section);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDragOver = (e) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  };

  const handleDrop = (e, targetSection) => {
    e.preventDefault();
    if (!draggedSection || draggedSection.id === targetSection.id) return;

    const sections = [...page.sections];
    const draggedIndex = sections.findIndex(s => s.id === draggedSection.id);
    const targetIndex = sections.findIndex(s => s.id === targetSection.id);

    sections.splice(draggedIndex, 1);
    sections.splice(targetIndex, 0, draggedSection);

    // Update positions
    const updatedSections = sections.map((s, index) => ({
      ...s,
      position: index
    }));

    setPage({ ...page, sections: updatedSections });
    setDraggedSection(null);

    // Save new order
    saveSectionOrder(updatedSections);
  };

  const saveSectionOrder = async (sections) => {
    try {
      const sectionIds = sections.map(s => s.id);
      await api.post('/admin/sections/reorder', { sectionIds });
    } catch (error) {
      console.error('Error saving section order:', error);
    }
  };

  const handleAddSection = async (sectionType) => {
    try {
      setSaving(true);

      const newSection = {
        type: sectionType,
        title: '',
        subtitle: '',
        content: '',
        position: page.sections.length,
        isEnabled: true
      };

      const response = await api.post(`/admin/pages/${pageId || page.id}/sections`, newSection);

      const createdSection = {
        ...response.data,
        cards: [],
        position: page.sections.length
      };

      setPage({
        ...page,
        sections: [...page.sections, createdSection]
      });

      setShowSectionModal(false);
    } catch (error) {
      console.error('Error creating section:', error);
      alert('Erreur lors de la création de la section');
    } finally {
      setSaving(false);
    }
  };

  const handleUpdateSection = async (sectionId, data) => {
    try {
      setSaving(true);

      await api.put(`/admin/sections/${sectionId}`, data);

      const sections = page.sections.map(s => 
        s.id === sectionId ? { ...s, ...data } : s
      );

      setPage({ ...page, sections });
      setShowSectionEditor(false);
      setEditingSection(null);
    } catch (error) {
      console.error('Error updating section:', error);
      alert('Erreur lors de la mise à jour');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteSection = async (sectionId) => {
    if (!window.confirm('Supprimer cette section ?')) return;

    try {
      await api.delete(`/admin/sections/${sectionId}`);

      const sections = page.sections.filter(s => s.id !== sectionId);
      setPage({ ...page, sections });
    } catch (error) {
      console.error('Error deleting section:', error);
      alert('Erreur lors de la suppression');
    }
  };

  const handleToggleSection = async (sectionId, isEnabled) => {
    try {
      await api.put(`/admin/sections/${sectionId}`, { isEnabled });

      const sections = page.sections.map(s => 
        s.id === sectionId ? { ...s, isEnabled } : s
      );

      setPage({ ...page, sections });
    } catch (error) {
      console.error('Error toggling section:', error);
    }
  };

  // Card management
  const handleAddCard = async (sectionId, cardData) => {
    try {
      setSaving(true);

      const response = await api.post(`/admin/sections/${sectionId}/cards`, {
        ...cardData,
        position: 0
      });

      const sections = page.sections.map(s => {
        if (s.id === sectionId) {
          return {
            ...s,
            cards: [...(s.cards || []), response.data]
          };
        }
        return s;
      });

      setPage({ ...page, sections });
      setShowCardModal(false);
    } catch (error) {
      console.error('Error creating card:', error);
      alert('Erreur lors de la création de la carte');
    } finally {
      setSaving(false);
    }
  };

  const handleUpdateCard = async (cardId, data) => {
    try {
      setSaving(true);

      await api.put(`/admin/cards/${cardId}`, data);

      const sections = page.sections.map(s => ({
        ...s,
        cards: s.cards?.map(c => c.id === cardId ? { ...c, ...data } : c)
      }));

      setPage({ ...page, sections });
      setShowCardModal(false);
      setEditingCard(null);
    } catch (error) {
      console.error('Error updating card:', error);
      alert('Erreur lors de la mise à jour');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteCard = async (cardId, sectionId) => {
    if (!window.confirm('Supprimer cette carte ?')) return;

    try {
      await api.delete(`/admin/cards/${cardId}`);

      const sections = page.sections.map(s => {
        if (s.id === sectionId) {
          return {
            ...s,
            cards: s.cards?.filter(c => c.id !== cardId)
          };
        }
        return s;
      });

      setPage({ ...page, sections });
    } catch (error) {
      console.error('Error deleting card:', error);
      alert('Erreur lors de la suppression');
    }
  };

  const getSectionTypeConfig = (type) => {
    return SECTION_TYPES.find(t => t.type === type) || { type, label: type, icon: 'fa-th-large' };
  };

  if (loading) {
    return (
      <AdminLayout>
        <div className="flex items-center justify-center min-h-[400px]">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-yellow-500"></div>
        </div>
      </AdminLayout>
    );
  }

  // Create new page mode
  if (!pageId && !page.id) {
    return (
      <AdminLayout>
        <PageCreateForm 
          page={page} 
          setPage={setPage} 
          onSave={async () => {
            try {
              setSaving(true);
              const response = await api.post('/admin/pages', page);
              navigate(`/admin/page-builder/${response.data.id}`);
            } catch (error) {
              alert('Erreur lors de la création');
            } finally {
              setSaving(false);
            }
          }}
          saving={saving}
        />
      </AdminLayout>
    );
  }

  return (
    <AdminLayout>
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 mb-6">
          <div className="p-6">
            <div className="flex items-center justify-between">
              <div>
                <button 
                  onClick={() => navigate('/admin/dashboard')}
                  className="text-sm text-gray-500 hover:text-gray-700 mb-2"
                >
                  ← Retour au tableau de bord
                </button>
                <h1 className="text-2xl font-bold text-gray-900">
                  {page.title || 'Nouvelle Page'}
                </h1>
                <p className="text-gray-500 text-sm">/{page.slug}</p>
              </div>
              <div className="flex items-center gap-3">
                <label className="flex items-center gap-2 cursor-pointer">
                  <input
                    type="checkbox"
                    checked={page.isPublished}
                    onChange={(e) => setPage({ ...page, isPublished: e.target.checked })}
                    className="w-5 h-5 text-yellow-500 rounded focus:ring-yellow-500"
                  />
                  <span className="text-sm text-gray-700">
                    {page.isPublished ? 'Publiée' : 'Brouillon'}
                  </span>
                </label>
                <button
                  onClick={handleSavePage}
                  disabled={saving}
                  className="bg-yellow-500 text-white px-6 py-2.5 rounded-lg hover:bg-yellow-600 font-medium disabled:opacity-50"
                >
                  {saving ? 'Sauvegarde...' : 'Sauvegarder'}
                </button>
              </div>
            </div>
          </div>

          {/* Page Settings */}
          <div className="px-6 pb-6 border-t border-gray-100">
            <details className="group">
              <summary className="cursor-pointer text-sm text-gray-500 hover:text-gray-700 py-3">
                Paramètres de la page (SEO)
              </summary>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-2">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Titre</label>
                  <input
                    type="text"
                    value={page.title}
                    onChange={(e) => setPage({ ...page, title: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Slug URL</label>
                  <input
                    type="text"
                    value={page.slug}
                    onChange={(e) => setPage({ ...page, slug: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Meta Titre (SEO)</label>
                  <input
                    type="text"
                    value={page.metaTitle || ''}
                    onChange={(e) => setPage({ ...page, metaTitle: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500"
                    placeholder="Titre pour les moteurs de recherche"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Meta Description (SEO)</label>
                  <textarea
                    value={page.metaDescription || ''}
                    onChange={(e) => setPage({ ...page, metaDescription: e.target.value })}
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500"
                    rows={2}
                    placeholder="Description pour les moteurs de recherche"
                  />
                </div>
              </div>
            </details>
          </div>
        </div>

        {/* Page Preview Link */}
        {pageId && page.isPublished && (
          <div className="mb-6">
            <a
              href={`/${page.slug}`}
              target="_blank"
              rel="noopener noreferrer"
              className="inline-flex items-center gap-2 text-blue-600 hover:text-blue-800"
            >
              <i className="fas fa-external-link-alt"></i>
              Voir la page publique
            </a>
          </div>
        )}

        {/* Sections */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100">
          <div className="p-5 border-b border-gray-100 flex items-center justify-between">
            <h2 className="text-lg font-bold text-gray-900">Sections de la page</h2>
            <button
              onClick={() => setShowSectionModal(true)}
              className="bg-yellow-500 text-white px-4 py-2 rounded-lg hover:bg-yellow-600 font-medium text-sm"
            >
              <i className="fas fa-plus mr-2"></i>
              Ajouter une section
            </button>
          </div>

          {/* Sections List */}
          {page.sections.length === 0 ? (
            <div className="p-12 text-center">
              <i className="fas fa-th-large text-4xl text-gray-300 mb-4"></i>
              <p className="text-gray-500">Aucune section ajoutée</p>
              <p className="text-gray-400 text-sm mt-2">
                Ajoutez vos premières sections pour commencer à construire votre page
              </p>
            </div>
          ) : (
            <div className="divide-y divide-gray-100">
              {page.sections.map((section, index) => {
                const typeConfig = getSectionTypeConfig(section.type);

                return (
                  <div
                    key={section.id}
                    draggable
                    onDragStart={(e) => handleDragStart(e, section)}
                    onDragOver={handleDragOver}
                    onDrop={(e) => handleDrop(e, section)}
                    className={`p-5 hover:bg-gray-50 transition-colors ${
                      !section.isEnabled ? 'opacity-50' : ''
                    }`}
                  >
                    <div className="flex items-start gap-4">
                      {/* Drag Handle */}
                      <div className="cursor-move p-2 text-gray-400 hover:text-gray-600">
                        <i className="fas fa-grip-vertical"></i>
                      </div>

                      {/* Type Icon */}
                      <div className={`w-12 h-12 rounded-lg flex items-center justify-center ${
                        section.isEnabled ? 'bg-yellow-100' : 'bg-gray-100'
                      }`}>
                        <i className={`fas ${typeConfig.icon} text-xl ${
                          section.isEnabled ? 'text-yellow-600' : 'text-gray-400'
                        }`}></i>
                      </div>

                      {/* Section Info */}
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center gap-3 mb-1">
                          <h3 className="font-medium text-gray-900">
                            {section.title || typeConfig.label}
                          </h3>
                          {!section.isEnabled && (
                            <span className="px-2 py-0.5 bg-gray-100 text-gray-600 text-xs rounded-full">
                              Désactivé
                            </span>
                          )}
                        </div>
                        <p className="text-sm text-gray-500">
                          {typeConfig.label} • Position: {index + 1}
                        </p>

                        {/* Cards preview */}
                        {section.cards && section.cards.length > 0 && (
                          <div className="mt-3 flex flex-wrap gap-2">
                            {section.cards.slice(0, 3).map((card) => (
                              <span 
                                key={card.id}
                                className="px-2 py-1 bg-gray-100 text-gray-600 text-xs rounded"
                              >
                                {card.title || 'Carte'}
                              </span>
                            ))}
                            {section.cards.length > 3 && (
                              <span className="px-2 py-1 text-gray-400 text-xs">
                                +{section.cards.length - 3} plus
                              </span>
                            )}
                          </div>
                        )}
                      </div>

                      {/* Actions */}
                      <div className="flex items-center gap-2">
                        <button
                          onClick={() => handleToggleSection(section.id, !section.isEnabled)}
                          className={`p-2 rounded-lg ${
                            section.isEnabled 
                              ? 'text-green-600 hover:bg-green-50' 
                              : 'text-gray-400 hover:bg-gray-100'
                          }`}
                          title={section.isEnabled ? 'Désactiver' : 'Activer'}
                        >
                          <i className={`fas ${section.isEnabled ? 'fa-eye' : 'fa-eye-slash'}`}></i>
                        </button>
                        <button
                          onClick={() => {
                            setEditingSection(section);
                            setShowSectionEditor(true);
                          }}
                          className="p-2 text-blue-600 hover:bg-blue-50 rounded-lg"
                          title="Modifier"
                        >
                          <i className="fas fa-edit"></i>
                        </button>
                        <button
                          onClick={() => {
                            setCardSectionId(section.id);
                            setEditingCard(null);
                            setShowCardModal(true);
                          }}
                          className="p-2 text-purple-600 hover:bg-purple-50 rounded-lg"
                          title="Ajouter une carte"
                        >
                          <i className="fas fa-plus-square"></i>
                        </button>
                        <button
                          onClick={() => handleDeleteSection(section.id)}
                          className="p-2 text-red-600 hover:bg-red-50 rounded-lg"
                          title="Supprimer"
                        >
                          <i className="fas fa-trash"></i>
                        </button>
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      </div>

      {/* Section Type Selection Modal */}
      {showSectionModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-xl w-full max-w-3xl max-h-[80vh] overflow-hidden">
            <div className="p-5 border-b border-gray-100 flex justify-between items-center">
              <h2 className="text-xl font-bold">Ajouter une section</h2>
              <button 
                onClick={() => setShowSectionModal(false)} 
                className="text-2xl text-gray-400 hover:text-gray-600"
              >
                ×
              </button>
            </div>
            <div className="p-5 overflow-y-auto max-h-[60vh]">
              <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                {SECTION_TYPES.map((type) => (
                  <button
                    key={type.type}
                    onClick={() => handleAddSection(type.type)}
                    className="p-4 border-2 border-gray-200 rounded-xl hover:border-yellow-500 hover:bg-yellow-50 text-left transition-colors"
                  >
                    <i className={`fas ${type.icon} text-2xl text-gray-600 mb-2`}></i>
                    <div className="font-medium text-gray-900">{type.label}</div>
                    <div className="text-xs text-gray-500 mt-1">{type.description}</div>
                  </button>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Section Editor Modal */}
      {showSectionEditor && editingSection && (
        <SectionEditorModal
          section={editingSection}
          onSave={handleUpdateSection}
          onClose={() => {
            setShowSectionEditor(false);
            setEditingSection(null);
          }}
        />
      )}

      {/* Card Editor Modal */}
      {showCardModal && (
        <CardEditorModal
          card={editingCard}
          sectionId={cardSectionId}
          onSave={editingCard 
            ? (data) => handleUpdateCard(editingCard.id, data)
            : (data) => handleAddCard(cardSectionId, data)
          }
          onClose={() => {
            setShowCardModal(false);
            setEditingCard(null);
          }}
        />
      )}
    </AdminLayout>
  );
}

// Page Creation Form Component
function PageCreateForm({ page, setPage, onSave, saving }) {
  return (
    <div className="max-w-2xl mx-auto bg-white rounded-xl shadow-sm border border-gray-100 p-8">
      <h1 className="text-2xl font-bold text-gray-900 mb-6">Créer une nouvelle page</h1>

      <div className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Titre de la page</label>
          <input
            type="text"
            value={page.title}
            onChange={(e) => setPage({ 
              ...page, 
              title: e.target.value,
              slug: e.target.value.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')
            })}
            className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500"
            placeholder="Mon Super Titre"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">URL de la page</label>
          <div className="flex items-center gap-2">
            <span className="text-gray-500">/</span>
            <input
              type="text"
              value={page.slug}
              onChange={(e) => setPage({ ...page, slug: e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, '') })}
              className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-yellow-500 focus:border-yellow-500"
              placeholder="mon-slug"
            />
          </div>
        </div>

        <div className="flex items-center gap-3">
          <input
            type="checkbox"
            id="isPublished"
            checked={page.isPublished}
            onChange={(e) => setPage({ ...page, isPublished: e.target.checked })}
            className="w-4 h-4 text-yellow-500 rounded focus:ring-yellow-500"
          />
          <label htmlFor="isPublished" className="text-sm text-gray-700">
            Publier immédiatement
          </label>
        </div>

        <button
          onClick={onSave}
          disabled={saving || !page.title || !page.slug}
          className="w-full bg-yellow-500 text-white px-6 py-3 rounded-lg hover:bg-yellow-600 font-medium disabled:opacity-50"
        >
          {saving ? 'Création...' : 'Créer la page'}
        </button>
      </div>
    </div>
  );
}

